    fout << "{\n";
    // Header
    fout << "  \"header\": {\n";
    fout << "    \"version\": \"" << hdr.szVersion << "\",\n";
    fout << "    \"meshCount\": " << hdr.nNumMeshes << ",\n";
    fout << "    \"animCount\": " << hdr.nNumAnimations << ",\n";
    fout << "    \"textureCount\": " << hdr.nNumTextures << ",\n";
    fout << "    \"byteAlignment\": " << MDF_BYTE_ALIGNMENT << ",\n";
    fout << "    \"totalDataSize\": " << hdr.nDataSize << "\n";
    fout << "  },\n";

    // Textures
    fout << "  \"textures\": [\n";
    for(unsigned int i=0;i<mdf.textureCount();++i){
      const char* t = mdf.texture(i);
      fout << "    \"" << (t?t:"") << "\"";
      if(i+1<mdf.textureCount()) fout << ",";
      fout << "\n";
    }
    fout << "  ],\n";

    // Animations
    fout << "  \"animations\": [\n";
    for(unsigned int ai=0; ai<mdf.animationCount(); ++ai){
      const TMdfAnimation* a = mdf.animation(ai);
      fout << "    {\n";
      fout << "      \"meshId\": " << a->nMeshId << ",\n";
      fout << "      \"timelineCount\": " << a->nNumTimelines << ",\n";
      fout << "      \"duration\": " << a->fDuration << ",\n";
      fout << "      \"timelines\": [\n";
      const TMdfTimeline* timelines = a->pTimelines;
      for(unsigned int ti=0; ti<a->nNumTimelines; ++ti){
        const TMdfTimeline& tl = timelines[ti];
        fout << "        {\n";
        fout << "          \"keyframeCount\": " << tl.nNumKeyframes << ",\n";
        fout << "          \"keyframes\": [\n";
        const TMdfKeyframe* kfs = tl.pKeyframes;
        for(unsigned int ki=0; ki<tl.nNumKeyframes; ++ki){
          const TMdfKeyframe& k = kfs[ki];
          fout << "            {\n";
          fout << "              \"time\": " << k.fTime << ",\n";
          fout << "              \"translation\": [" << k.tTranslation.x << ", " << k.tTranslation.y << ", " << k.tTranslation.z << "],\n";
          fout << "              \"rotation\": [" << k.tRotation.x << ", " << k.tRotation.y << ", " << k.tRotation.z << ", " << k.tRotation.w << "],\n";
          fout << "              \"scale\": [" << k.tScale.x << ", " << k.tScale.y << ", " << k.tScale.z << "]\n";
          fout << "            }" << (ki+1<tl.nNumKeyframes? "," : "") << "\n";
        }
        fout << "          ]\n";
        fout << "        }" << (ti+1<a->nNumTimelines? "," : "") << "\n";
      }
      fout << "      ]\n";
      fout << "    }" << (ai+1<mdf.animationCount()? "," : "") << "\n";
    }
    fout << "  ],\n";

    // Meshes
    fout << "  \"meshes\": [\n";
    for(unsigned int mi=0; mi<mdf.meshCount(); ++mi){
      const TMdfMesh* m = mdf.mesh(mi);
      fout << "    {\n";
      fout << "      \"vertexCount\": " << m->nNumVertices << ",\n";
      fout << "      \"indexCount\": " << m->nNumIndices << ",\n";
      fout << "      \"jointCount\": " << m->nNumJoints << ",\n";
      fout << "      \"textureIndex\": " << m->nTextureIndex << ",\n";
      fout << "      \"type\": \"" << (m->nNumJoints>0? "skinned":"static") << "\",\n";
      fout << "      \"vertices\": [\n";
      const TMdfVertex* verts = m->pVertices;
      for(unsigned int vi=0; vi<m->nNumVertices; ++vi){
        const TMdfVertex& v = verts[vi];
        fout << "        {\n";
        fout << "          \"position\": [" << v.tPosition.x << ", " << v.tPosition.y << ", " << v.tPosition.z << "],\n";
        if(m->nNumJoints>0){
          fout << "          \"weights\": [" << v.tWeights.x << ", " << v.tWeights.y << ", " << v.tWeights.z << "],\n";
          fout << "          \"bones\": [" << (int)v.vBones[0] << ", " << (int)v.vBones[1] << ", " << (int)v.vBones[2] << ", " << (int)v.vBones[3] << "],\n";
        }
        fout << "          \"normal\": [" << v.tNormal.x << ", " << v.tNormal.y << ", " << v.tNormal.z << "],\n";
        fout << "          \"texcoord\": [" << v.tTexcoord.x << ", " << v.tTexcoord.y << "]\n";
        fout << "        }" << (vi+1<m->nNumVertices? "," : "") << "\n";
      }
      fout << "      ],\n";
      // indices
      fout << "      \"indices\": [";
      const unsigned int* idx = m->pIndices;
      for(unsigned int ii=0; ii<m->nNumIndices; ++ii){ fout << idx[ii]; if(ii+1<m->nNumIndices) fout << ","; }
      fout << "],\n";
      if(m->nNumJoints>0){
        // bindPose matrices: assume 16-float per matrix
        fout << "      \"bindPose\": [\n";
        const float* mats = m->pBindPoseMats;
        for(unsigned int bi=0; bi<m->nNumJoints; ++bi){
          const float* mat = mats + bi*16;
          fout << "        [";
          for(int k=0;k<16;++k){ fout << mat[k]; if(k+1<16) fout << ", "; }
          fout << "]" << (bi+1<m->nNumJoints? "," : "") << "\n";
        }
        fout << "      ],\n";
        // parentInfo
        fout << "      \"parentInfo\": [";
        const int* parents = m->pParentInfo;
        for(unsigned int pi=0; pi<m->nNumJoints; ++pi){ fout << parents[pi]; if(pi+1<m->nNumJoints) fout << ","; }
        fout << "]\n";
      } else {
        // remove trailing comma if needed by writing newline
        fout.seekp(-2, std::ios_base::cur);
        fout << "\n";
      }
      fout << "    }" << (mi+1<mdf.meshCount()? "," : "") << "\n";
    }
    fout << "  ]\n";

    fout << "}\n";
    return 0;
  } catch(const std::exception& e){ std::cerr << "Error: " << e.what() << "\n"; return 1; }
}
