#include <cstdio>
#include <cstdlib>
#include <string>
#include <vector>
#include <fstream>
#include <iostream>
#include "MdfFormat.h"
#include "mdftypes.h"

class MdfFormatView : public MdfFormat {
public:
    const MdfHeader& header() const { return m_tMdfHeader; }
    unsigned int meshCount() const { return m_tMdfHeader.nNumMeshes; }
    unsigned int animationCount() const { return m_tMdfHeader.nNumAnimations; }
    unsigned int textureCount() const { return m_tMdfHeader.nNumTextures; }
    const TMdfMesh* mesh(unsigned int i) const { return m_vpMeshes + i; }
    const TMdfAnimation* animation(unsigned int i) const { return m_vpAnimations + i; }
    const char* texture(unsigned int i) const { return m_vpTextures ? m_vpTextures[i] : nullptr; }
};

static void usage(const char* arg0){ std::cerr << "Usage: " << arg0 << " <input file> <output json>\n"; }

static void write_vertices(std::ostream& fout, const TMdfMesh* m){
  // Determine if mesh is skinned by joint count or layout flag
  bool skinned = (m->nNumJoints > 0);
  fout << "      \"vertices\": [\n";
  if(skinned){
    const TMdfVertSkn* verts = reinterpret_cast<const TMdfVertSkn*>(m->pVerts);
    for(unsigned int vi=0; vi<m->nNumVerts; ++vi){
      const TMdfVertSkn& v = verts[vi];
      fout << "        {\n";
      fout << "          \"position\": [" << v.tPosition.x << ", " << v.tPosition.y << ", " << v.tPosition.z << "],\n";
      fout << "          \"weights\": [" << v.tWeights.x << ", " << v.tWeights.y << ", " << v.tWeights.z << "],\n";
      fout << "          \"bones\": [" << (int)v.vBones[0] << ", " << (int)v.vBones[1] << ", " << (int)v.vBones[2] << ", " << (int)v.vBones[3] << "],\n";
      fout << "          \"normal\": [" << v.tNormal.x << ", " << v.tNormal.y << ", " << v.tNormal.z << "],\n";
      fout << "          \"texcoord\": [" << v.tTexcoord.x << ", " << v.tTexcoord.y << "]\n";
      fout << "        }" << (vi+1<m->nNumVerts? "," : "") << "\n";
    }
  } else {
    const TMdfVertSta* verts = reinterpret_cast<const TMdfVertSta*>(m->pVerts);
    for(unsigned int vi=0; vi<m->nNumVerts; ++vi){
      const TMdfVertSta& v = verts[vi];
      fout << "        {\n";
      fout << "          \"position\": [" << v.tPosition.x << ", " << v.tPosition.y << ", " << v.tPosition.z << "],\n";
      fout << "          \"normal\": [" << v.tNormal.x << ", " << v.tNormal.y << ", " << v.tNormal.z << "],\n";
      fout << "          \"texcoord\": [" << v.tTexcoord.x << ", " << v.tTexcoord.y << "]\n";
      fout << "        }" << (vi+1<m->nNumVerts? "," : "") << "\n";
    }
  }
  fout << "      ],\n";
}

int main(int argc, char** argv){
  if(argc != 3){ usage(argv[0]); return 1; }
  std::string in = argv[1];
  std::string out = argv[2];
  try {
    MdfFormatView mdf;
    if(!mdf.CreateFromFile(in.c_str())){ std::cerr << "Failed to load: " << in << "\n"; return 1; }
    std::ofstream fout(out);
    if(!fout){ std::cerr << "Failed to open output: " << out << "\n"; return 1; }

    const MdfHeader& hdr = mdf.header();
    fout << "{\n";
    // Header
    fout << "  \"header\": {\n";
    fout << "    \"version\": \"" << hdr.szVersion << "\",\n";
    fout << "    \"meshCount\": " << hdr.nNumMeshes << ",\n";
    fout << "    \"animCount\": " << hdr.nNumAnimations << ",\n";
    fout << "    \"textureCount\": " << hdr.nNumTextures << ",\n";
    fout << "    \"byteAlignment\": " << MDF_BYTE_ALIGNMENT << ",\n";
    fout << "    \"totalDataSize\": " << hdr.nDataSize << "\n";
    fout << "  },\n";

    // Textures
    fout << "  \"textures\": [\n";
    for(unsigned int i=0;i<mdf.textureCount();++i){
      const char* t = mdf.texture(i);
      fout << "    \"" << (t?t:"") << "\"";
      if(i+1<mdf.textureCount()) fout << ",";
      fout << "\n";
    }
    fout << "  ],\n";

    // Animations
    fout << "  \"animations\": [\n";
    for(unsigned int ai=0; ai<mdf.animationCount(); ++ai){
      const TMdfAnimation* a = mdf.animation(ai);
      fout << "    {\n";
      fout << "      \"meshId\": " << a->nMeshId << ",\n";
      fout << "      \"timelineCount\": " << a->nNumTimelines << ",\n";
      fout << "      \"duration\": " << a->fDuration << ",\n";
      fout << "      \"timelines\": [\n";
      const TMdfTimeline* timelines = a->pTimelines;
      for(unsigned int ti=0; ti<a->nNumTimelines; ++ti){
        const TMdfTimeline& tl = timelines[ti];
        fout << "        {\n";
        fout << "          \"keyframeCount\": " << tl.nNumKeyframes << ",\n";
        fout << "          \"keyframes\": [\n";
        const TMdfKeyframe* kfs = tl.pKeyframes;
        for(unsigned int ki=0; ki<tl.nNumKeyframes; ++ki){
          const TMdfKeyframe& k = kfs[ki];
          fout << "            {\n";
          fout << "              \"time\": " << k.fTime << ",\n";
          fout << "              \"translation\": [" << k.tTranslation.x << ", " << k.tTranslation.y << ", " << k.tTranslation.z << "],\n";
          fout << "              \"rotation\": [" << k.tRotation.x << ", " << k.tRotation.y << ", " << k.tRotation.z << ", " << k.tRotation.w << "],\n";
          fout << "              \"scale\": [" << k.tScale.x << ", " << k.tScale.y << ", " << k.tScale.z << "]\n";
          fout << "            }" << (ki+1<tl.nNumKeyframes? "," : "") << "\n";
        }
        fout << "          ]\n";
        fout << "        }" << (ti+1<a->nNumTimelines? "," : "") << "\n";
      }
      fout << "      ]\n";
      fout << "    }" << (ai+1<mdf.animationCount()? "," : "") << "\n";
    }
    fout << "  ],\n";

    // Meshes
    fout << "  \"meshes\": [\n";
    for(unsigned int mi=0; mi<mdf.meshCount(); ++mi){
      const TMdfMesh* m = mdf.mesh(mi);
      fout << "    {\n";
      fout << "      \"vertexCount\": " << m->nNumVerts << ",\n";
      fout << "      \"indexCount\": " << m->nNumIndices << ",\n";
      fout << "      \"jointCount\": " << m->nNumJoints << ",\n";
      fout << "      \"textureIndex\": " << m->nTextureIndex << ",\n";
      fout << "      \"type\": \"" << (m->nNumJoints>0? "skinned":"static") << "\",\n";
      write_vertices(fout, m);
      // indices (assume 32-bit indices stored contiguously after header relocation)
      fout << "      \"indices\": [";
      const unsigned int* idx32 = reinterpret_cast<const unsigned int*>(m->pIndices32);
      if(idx32){
        for(unsigned int ii=0; ii<m->nNumIndices; ++ii){ fout << idx32[ii]; if(ii+1<m->nNumIndices) fout << ","; }
      } else {
        // fallback to 16-bit if provided
        const unsigned short* idx16 = reinterpret_cast<const unsigned short*>(m->pIndices16);
        for(unsigned int ii=0; ii<m->nNumIndices; ++ii){ fout << idx16[ii]; if(ii+1<m->nNumIndices) fout << ","; }
      }
      fout << "],\n";
      if(m->nNumJoints>0){
        // bindPose matrices
        fout << "      \"bindPose\": [\n";
        const float* mats = m->pBindPose;
        for(unsigned int bi=0; bi<m->nNumJoints; ++bi){
          const float* mat = mats + bi*16;
          fout << "        [";
          for(int k=0;k<16;++k){ fout << mat[k]; if(k+1<16) fout << ", "; }
          fout << "]" << (bi+1<m->nNumJoints? "," : "") << "\n";
        }
        fout << "      ],\n";
        // parentInfo
        fout << "      \"parentInfo\": [";
        const int* parents = m->pParent;
        for(unsigned int pi=0; pi<m->nNumJoints; ++pi){ fout << parents[pi]; if(pi+1<m->nNumJoints) fout << ","; }
        fout << "]\n";
      } else {
        // remove trailing comma if needed by writing newline
        fout.seekp(-2, std::ios_base::cur);
        fout << "\n";
      }
      fout << "    }" << (mi+1<mdf.meshCount()? "," : "") << "\n";
    }
    fout << "  ]\n";

    fout << "}\n";
    return 0;
  } catch(const std::exception& e){ std::cerr << "Error: " << e.what() << "\n"; return 1; }
}
