class MdfFormatView : public MdfFormat {
public:
    const MdfHeader& header() const { return m_tMdfHeader; }
    unsigned int meshCount() const { return m_tMdfHeader.nNumMeshes; }
    unsigned int animationCount() const { return m_tMdfHeader.nNumAnimations; }
