static void usage(const char* arg0){ std::cerr << "Usage: " << arg0 << " <input file> <output json>\n"; }

static void write_vertices(std::ostream& fout, const TMdfMesh* m){
  bool skinned = (m->nNumJoints > 0);
  fout << "      \"vertices\": [\n";
  if(skinned){
    const TMdfVertSkn* verts = reinterpret_cast<const TMdfVertSkn*>(m->pVerts);
    for(unsigned int vi=0; vi<m->nNumVerts; ++vi){
      const TMdfVertSkn& v = verts[vi];
      fout << "        {\n";
      fout << "          \"position\": [" << v.tPosition.x << ", " << v.tPosition.y << ", " << v.tPosition.z << "],\n";
      fout << "          \"weights\": [" << v.tWeights.x << ", " << v.tWeights.y << ", " << v.tWeights.z << "],\n";
      fout << "          \"bones\": [" << (int)v.vBones[0] << ", " << (int)v.vBones[1] << ", " << (int)v.vBones[2] << ", " << (int)v.vBones[3] << "],\n";
      fout << "          \"normal\": [" << v.tNormal.x << ", " << v.tNormal.y << ", " << v.tNormal.z << "],\n";
      fout << "          \"texcoord\": [" << v.tTexcoord.x << ", " << v.tTexcoord.y << "]\n";
      fout << "        }" << (vi+1<m->nNumVerts? "," : "") << "\n";
    }
  } else {
    const TMdfVertSta* verts = reinterpret_cast<const TMdfVertSta*>(m->pVerts);
    for(unsigned int vi=0; vi<m->nNumVerts; ++vi){
      const TMdfVertSta& v = verts[vi];
      fout << "        {\n";
      fout << "          \"position\": [" << v.tPosition.x << ", " << v.tPosition.y << ", " << v.tPosition.z << "],\n";
      fout << "          \"normal\": [" << v.tNormal.x << ", " << v.tNormal.y << ", " << v.tNormal.z << "],\n";
      fout << "          \"texcoord\": [" << v.tTexcoord.x << ", " << v.tTexcoord.y << "]\n";
      fout << "        }" << (vi+1<m->nNumVerts? "," : "") << "\n";
    }
  }
  fout << "      ],\n";
}

int main(int argc, char** argv){
  if(argc != 3){ usage(argv[0]); return 1; }
