      }
      fout << "      ]\n";
      fout << "    }" << (ai+1<mdf.animationCount()? "," : "") << "\n";
    }
    fout << "  ],\n";

    // Meshes
    fout << "  \"meshes\": [\n";
    for(unsigned int mi=0; mi<mdf.meshCount(); ++mi){
      const TMdfMesh* m = mdf.mesh(mi);
      fout << "    {\n";
      fout << "      \"vertexCount\": " << m->nNumVerts << ",\n";
      fout << "      \"indexCount\": " << m->nNumIndices << ",\n";
      fout << "      \"jointCount\": " << m->nNumJoints << ",\n";
