      }
      fout << "    }" << (mi+1<mdf.meshCount()? "," : "") << "\n";
    }
    fout << "  ]\n";

    fout << "}\n";
    return 0;
  } catch(const std::exception& e){ std::cerr << "Error: " << e.what() << "\n"; return 1; }
