};

static void usage(const char* arg0){ std::cerr << "Usage: " << arg0 << " <input file> <output json>\n"; }

static void write_vertices(std::ostream& fout, const TMdfMesh* m){
  bool skinned = (m->nNumJoints > 0);
  fout << "      \"vertices\": [\n";
  if(skinned){
    // Skinned vertices
    const TMdfVertSkn* verts = reinterpret_cast<const TMdfVertSkn*>(m->uVerts.pVerts);
    for(unsigned int vi=0; vi<m->nNumVerts; ++vi){
      const TMdfVertSkn& v = verts[vi];
      fout << "        {\n";
      fout << "          \"position\": [" << v.position.x << ", " << v.position.y << ", " << v.position.z << "],\n";
      fout << "          \"weights\": [" << v.weights.x << ", " << v.weights.y << ", " << v.weights.z << "],\n";
      fout << "          \"bones\": [" << (int)v.bones[0] << ", " << (int)v.bones[1] << ", " << (int)v.bones[2] << ", " << (int)v.bones[3] << "],\n";
      fout << "          \"normal\": [" << v.normal.x << ", " << v.normal.y << ", " << v.normal.z << "],\n";
      fout << "          \"texcoord\": [" << v.texcoord.x << ", " << v.texcoord.y << "]\n";
      fout << "        }" << (vi+1<m->nNumVerts? "," : "") << "\n";
    }
  } else {
    // Static vertices
    const TMdfVertSta* verts = reinterpret_cast<const TMdfVertSta*>(m->uVerts.pVerts);
    for(unsigned int vi=0; vi<m->nNumVerts; ++vi){
      const TMdfVertSta& v = verts[vi];
      fout << "        {\n";
      fout << "          \"position\": [" << v.position.x << ", " << v.position.y << ", " << v.position.z << "],\n";
      fout << "          \"normal\": [" << v.normal.x << ", " << v.normal.y << ", " << v.normal.z << "],\n";
      fout << "          \"texcoord\": [" << v.texcoord.x << ", " << v.texcoord.y << "]\n";
      fout << "        }" << (vi+1<m->nNumVerts? "," : "") << "\n";
    }
  }
  fout << "      ],\n";
}

int main(int argc, char** argv){
  if(argc != 3){ usage(argv[0]); return 1; }
  std::string in = argv[1];
  std::string out = argv[2];
  try {
    MdfFormatView mdf;
    if(!mdf.CreateFromFile(in.c_str())){ std::cerr << "Failed to load: " << in << "\n"; return 1; }
    std::ofstream fout(out);
    if(!fout){ std::cerr << "Failed to open output: " << out << "\n"; return 1; }

    const MdfHeader& hdr = mdf.header();
    fout << "{\n";
    // Header
    fout << "  \"header\": {\n";
    fout << "    \"version\": \"MDF\",\n";
    fout << "    \"meshCount\": " << mdf.meshCount() << ",\n";
    fout << "    \"animCount\": " << mdf.animationCount() << ",\n";
    fout << "    \"textureCount\": " << mdf.textureCount() << ",\n";
    fout << "    \"byteAlignment\": " << MDF_BYTE_ALIGNMENT << ",\n";
    fout << "    \"totalDataSize\": " << hdr.nTotalDataSize << "\n";
    fout << "  },\n";

    // Textures
    fout << "  \"textures\": [\n";
    for(unsigned int i=0;i<mdf.textureCount();++i){
      const char* t = mdf.texture(i);
      fout << "    \"" << (t?t:"") << "\"";
      if(i+1<mdf.textureCount()) fout << ",";
      fout << "\n";
    }
    fout << "  ],\n";

    // Animations
    fout << "  \"animations\": [\n";
    for(unsigned int ai=0; ai<mdf.animationCount(); ++ai){
      const TMdfAnimation* a = mdf.animation(ai);
      fout << "    {\n";
      fout << "      \"meshId\": " << a->hMeshId << ",\n";
      // Duration may not be stored explicitly; emit 0.0 if not present
      fout << "      \"timelineCount\": " << a->nNumTimelines << ",\n";
      fout << "      \"duration\": 0.0,\n";
      fout << "      \"timelines\": [\n";
      const TMdfTimeline* tlArr = a->pTimelines;
      for(unsigned int ti=0; ti<a->nNumTimelines; ++ti){
        const TMdfTimeline& tl = tlArr[ti];
        fout << "        {\n";
        fout << "          \"keyframeCount\": " << tl.nKeyFrames << ",\n";
        fout << "          \"keyframes\": [\n";
        const TMdfKeyframe* kfs = tl.pKeyFrames;
        for(unsigned int ki=0; ki<tl.nKeyFrames; ++ki){
          const TMdfKeyframe& k = kfs[ki];
          fout << "            {\n";
          fout << "              \"time\": " << k.fKeyTime << ",\n";
          fout << "              \"translation\": [" << k.vecTranslation.x << ", " << k.vecTranslation.y << ", " << k.vecTranslation.z << "],\n";
          fout << "              \"rotation\": [" << k.qRotation.x << ", " << k.qRotation.y << ", " << k.qRotation.z << ", " << k.qRotation.w << "],\n";
          fout << "              \"scale\": [" << k.vecScale.x << ", " << k.vecScale.y << ", " << k.vecScale.z << "]\n";
          fout << "            }" << (ki+1<tl.nKeyFrames? "," : "") << "\n";
        }
        fout << "          ]\n";
        fout << "        }" << (ti+1<a->nNumTimelines? "," : "") << "\n";
      }
      fout << "      ]\n";
      fout << "    }" << (ai+1<mdf.animationCount()? "," : "") << "\n";
    }
    fout << "  ],\n";

    // Meshes
    fout << "  \"meshes\": [\n";
    for(unsigned int mi=0; mi<mdf.meshCount(); ++mi){
      const TMdfMesh* m = mdf.mesh(mi);
      fout << "    {\n";
      fout << "      \"vertexCount\": " << m->nNumVerts << ",\n";
      fout << "      \"indexCount\": " << m->nNumIndices << ",\n";
      fout << "      \"jointCount\": " << m->nNumJoints << ",\n";
      fout << "      \"textureIndex\": " << m->hTexture << ",\n";
      fout << "      \"type\": \"" << (m->nNumJoints>0? "skinned":"static") << "\",\n";
      write_vertices(fout, m);
      // Indices (16-bit)
      fout << "      \"indices\": [";
      const unsigned short* idx = m->uIdxs.pIndices;
      for(unsigned int ii=0; ii<m->nNumIndices; ++ii){ fout << idx[ii]; if(ii+1<m->nNumIndices) fout << ","; }
      fout << "],\n";
      if(m->nNumJoints>0){
        // Bind pose matrices (TMdfMatrix4*) serialized as 16 floats
        fout << "      \"bindPose\": [\n";
        TMdfMatrix4* mats = m->uBnd.pBindMats;
        for(unsigned int bi=0; bi<m->nNumJoints; ++bi){
          const TMdfMatrix4& mat = mats[bi];
          const float* f = reinterpret_cast<const float*>(&mat);
          fout << "        [";
          for(int k=0;k<16;++k){ fout << f[k]; if(k+1<16) fout << ", "; }
          fout << "]" << (bi+1<m->nNumJoints? "," : "") << "\n";
        }
        fout << "      ],\n";
        // Parent info
        fout << "      \"parentInfo\": [";
        const int* parents = m->uPrnt.pParentInfo;
        for(unsigned int pi=0; pi<m->nNumJoints; ++pi){ fout << parents[pi]; if(pi+1<m->nNumJoints) fout << ","; }
        fout << "]\n";
      }
      fout << "    }" << (mi+1<mdf.meshCount()? "," : "") << "\n";
    }
    fout << "  ]\n";

    fout << "}\n";
    return 0;
  } catch(const std::exception& e){ std::cerr << "Error: " << e.what() << "\n"; return 1; }
}
